import{z}from"zod";import{getWebSocketServerForUIProTool,checkWebSocketServerForUIProTool}from"./utils.js";import{getQuickReferenceNotes,getUsagePatterns,getWorkflowSteps}from"./componentConfigPrompts.js";export const TOOL_NAME_GET_MAPPING_CONFIG="generateComponentsConfig";export const TOOL_DEFINITION_GET_MAPPING_CONFIG={name:"generateComponentsConfig",description:"Use this tool to get the config schema for design components, predict their code mapping (map components in code with components in design file), and save it to locofy.config.json in workspace root directory.",inputSchema:{type:"object",properties:{components:{type:"array",items:{type:"string"},description:"Array of components user want to generate mapping config for."}},required:["components"],prerequisites:["UIPro Figma plugin installed and connected","Frame(s)/component(s) selected in the design file"],workflow:["For EACH component file do these step:","1. Read and analyze the component source code to extract props/types","2. Predict mapping between code and design component(s)","3. For each component, generate a config object","4. Write or merge this entry into locofy.config.json at the workspace root diretory"]}};export const TOOL_SCHEMA_GET_MAPPING_CONFIG=z.object({});export async function runToolGetMappingConfig(_args){const webSocketServer=getWebSocketServerForUIProTool(),serverCheckResult=checkWebSocketServerForUIProTool(webSocketServer);if(!serverCheckResult.valid)return serverCheckResult.data;const result={content:[]},designComponentsResult=await webSocketServer.sendDesignComponentsRequest();if(!designComponentsResult?.success){return{isError:!0,content:[{type:"text",text:`${designComponentsResult?.error||"Unknown error occurred during code retrieval from UIPro plugin"}. Stop the process and inform the user about the error.`}]}}const projectInfo=webSocketServer.getProjectInfo(),mappingJSONPrompt=getMappingConfigPrompt(projectInfo?.framework||null);result.content.push({type:"text",text:JSON.stringify(mappingJSONPrompt,null,2)}),result.content.push({type:"text",text:"Below is the design components data sent from UIPro plugin, use this data to help you generate the mapping config for the components."});return(designComponentsResult.data||[]).forEach((designComponent=>{result.content.push({type:"image",mimeType:"image/jpeg",data:designComponent.image}),result.content.push({type:"text",text:`\n\n      Component name: ${designComponent.name}\n      Component props: ${JSON.stringify(designComponent.props,null,2)}\n      Component structure: ${JSON.stringify(designComponent.structure,null,2)}\n\n`})})),result}function getMappingConfigPrompt(framework){return{name:"LocofyMappingSchema",version:"1.0.0",schema_kind:"json_schema_draft_07",schema:{$schema:"http://json-schema.org/draft-07/schema#",title:"LocofyConfigFile",type:"object",additionalProperties:!1,properties:{components:{type:"array",description:"List of component entries for Locofy configuration.",items:{$ref:"#/$defs/Component"}}},required:["components"],$defs:{Component:{type:"object",additionalProperties:!1,properties:{path:{type:"string",description:"Relative path to the component source file (e.g., ./src/components/Button.tsx, ./src/components/button.component.ts, ./src/directives/loading.directive.ts)."},name:{type:"string",description:"Component name as exported from the source file. For Angular components, use its selector as the component name."},props:{type:"array",description:"List of prop definitions.",items:{$ref:"#/$defs/Prop"}},directives:{type:"array",description:"Angular-specific: List of CUSTOM PROJECT directive dependencies for this component. Only include directives defined within the project (relative paths). Exclude Angular built-in, Material, and third-party library directives.",items:{$ref:"#/$defs/Directive"}},module:{type:"string",description:"Angular-specific: Path to the module file if component is defined in a module (e.g., ./src/components/header.locofy.module.ts)."},config:{type:"object",description:"How mapping config for this component is configured.",properties:{layerName:{type:"string",description:"Name of the design layer that this component is mapped to. Based on the design component data sent below, each component has its tree structure, props, name and image, use those data to predict the correct layer prepresend this component on the design. If can not find any layer to map to, ignore this field. One component can only be map to one layer. And one layer can also be mapped to one component."}}}},required:["path"],anyOf:[{required:["name","props"]},{required:["directives"]},{required:["module"]}]},DefaulValue:{anyOf:[{type:"string"},{type:"number"},{type:"boolean"},{type:"object",additionalProperties:!0},{type:"array"}],description:"Allowed for defaultValue. Component instance values are not supported. If you cannot extract a value, leave it empty."},Prop:{type:"object",additionalProperties:!1,properties:{name:{type:"string",description:"Prop name."},dataType:{type:"string",enum:["string","number","boolean","enum","node","function","object","array"],description:"Supported prop types. Props with type node are props that need to send a HTML node as value."},propType:{type:"number",enum:[1,2,3,4,5],description:["How the prop used in the component:","1: Value prop (e.g. text, number, boolean, enum, object, array), Special case: prop is className, it should be 1, moreover if a prop is an enum, it should be value prop ;","2: Style prop, only if prop used inside style value (e.g. backgroudColor, textColor,...);","3: action prop (e.g. onClick, onHover, ...);","4: conditional rendering prop (e.g. showIcon, showText, ...);","5: node prop / slot prop (e.g. children, innerContent,...);"].join(" ")},isOptional:{type:"boolean",default:!1,description:"Whether the prop is optional. Only add this field if prop is optional, if it is required, ignore this field."},attr:{type:"string",description:"HTML attribute to bind (e.g., 'src', 'href')."},imageResolveType:{type:"string",enum:["require","uri"],description:'Only exist if attr is "src", this field only used for React Native image, to let us know how user want to resolve the image path. For example, it in the code they use require("path/to/image.png") to resolve the image path, then this field should be "require", if they use {uri:"path/to/image.png"} to resolve the image path, then this field should be "uri".'},defaultValue:{$ref:"#/$defs/DefaultPreviewValue"},keys:{type:"array",item:{$ref:"#/$defs/Prop"},description:"If prop is an object, this is array of object keys, if a key is also object, it will have a nested keys inside. If prop is array of object, it only has one key: 0, and this key will have sub keys which are fiels of item object"},expectValues:{type:"array",items:{anyOf:[{type:"string"},{type:"number"},{type:"boolean"}]},minItems:1,description:"Allowed values when type is 'enum'. Array of valid values for prop."},config:{type:"object",description:["How mapping config for this prop is configured.","VALIDATION CHECKLIST:","Step 1: Make sure all type compatibility and constraints are met.","Step 2: Make sure only use one of the layerProp or layer field. If have both only use the most possible one."].join("\n"),properties:{layerProp:{type:"string",description:["Name of the design property that this prop is mapped to. Based on the design component data sent below, each design component has a set of property that can be used to map to the component prop.","CRITICAL TYPE COMPATIBILITY FOR PROPERTY MAPPING RULES:","- 'node' type props can ONLY map to 'node' type design props (never to boolean, string, etc.). If no compatible design prop exists, use 'layer' mapping instead","If can not find any property with compatible type to map to, ignore this field and use 'layer' mapping."].join("\n")},layer:{type:"object",properties:{name:{type:"string",description:["Name of the design layer that this prop is mapped to.","IMPORTANT CONSTRAINTS:","- One layer CAN be mapped to multiple props","- BUT each layer can only be mapped to ONE 'node' type prop","- The same layer can be mapped to multiple non-node props (boolean, string, number, etc.) AND one node prop","- Example: A layer can map to showIcon (boolean) + leftIcon (node), but NOT to both leftIcon (node) and rightIcon (node)","If multiple node-type props would map to the same layer, only map the most possible one."].join("\n")},selector:{type:"string",description:'Optional, only used for some advanced cases. We currently have only one selector: "children".\n                      - children: use this selector when want to target children of selected layer. For example, if the selected layer is a container layer, and you want to target the children of the container layer, you can use this selector. Because we can only select one layer at a time.'}},description:"Design layer that this prop is mapped to. Based on the design component data sent below, each design component has its own tree structure, try to find if this prop can be mapped to a layer. If can not find any layer to map to, ignore this field. Prop can only be mapped to one layer. But a layer can be mapped to multiple props. If this prop already mapped to a layer prop via layerProp field, ignore this field."},valueMapping:{type:"object",description:["Mapping between component prop value and design component prop values (if both are enum and have expected values and those values are not totally the same).","The object keys are values of the component prop, the object values are arrays of valid design component prop values.","Make sure each design value can appear in ONLY ONE mapping (injective function). However, one component value CAN map to multiple design values.","If component has more values than design, leave some component values unmapped rather than creating duplicate design value mappings.","Can have cases that a component prop value can not map to any design component prop value, then do not include in in the result, the result only include props that have valid mapping.","CRITICAL CONSTRAINT: Each design value can appear in ONLY ONE mapping (injective function). However, one component value CAN map to multiple design values.","Valid Examples:","- {'md': ['medium', 'large']} ✓ One component value maps to multiple design values","- {'sm': ['small'], 'md': ['medium'], 'lg': ['large']} ✓ 1-to-1 mapping","Invalid Examples:","- {'sm': ['small'], 'md': ['small']} ✗ Design value 'small' appears twice","- {'sm': ['medium'], 'md': ['medium']} ✗ Design value 'medium' is duplicated","VALIDATION CHECKLIST - Complete BEFORE finalizing valueMapping:","Step 1: List ALL design values available","Step 2: Create initial mapping candidates","Step 3: CHECK: Does ANY design value appear more than once across ALL arrays?","Step 4: If YES to Step 3, REMOVE mappings until each design value appears EXACTLY ONCE"].join("\n")}}}},required:["name","type"],allOf:[{if:{properties:{type:{const:"enum"}},required:["type"]},then:{required:["enum"]}},{if:{properties:{type:{const:"node"}},required:["type"]},then:{not:{required:["defaultValue"]}}},{if:{properties:{type:{const:"function"}},required:["type"]},then:{not:{required:["defaultValue"]}}}]},Directive:{type:"object",additionalProperties:!1,properties:{path:{type:"string",description:"Relative path to the CUSTOM PROJECT directive source file (e.g., ./src/directives/loading.directive.ts). Must start with ./ or ../ (no @angular/* or node_modules paths)."},selector:{type:"string",description:'Custom project directive selector (e.g., "ds-loading", "app-tooltip"). Exclude Angular built-in selectors (mat-*, fx-, ng*).'}},required:["path","selector"]}}},quick_reference:{types:["string","number","boolean","enum","node","function","object","array"],notes:getQuickReferenceNotes(framework),usage_patterns:getUsagePatterns(framework),constraints:["Do not create any new file or directory, except the locofy.config.json file (only if it not exist).","If user want to process a component that not exist, ignore this component."].join("\n"),workflow_steps:getWorkflowSteps(framework)}}}